.social-btn svg {
  width: 16px;
  height: 16px;
}

.switch-auth {
  font-size: 0.84rem;
  color: #6b7280;
  text-align: center;
  margin-top: 1.2rem;
}

.switch-auth button {
  background: none;
  border: none;
